import { describe, expect, it } from "vitest";
import { renderToStaticMarkup } from "react-dom/server";

import OrdersPage from "./page";

// We re-render the page-level helpers via a tiny inline component because
// they are not exported. The static-markup smoke test is enough to assert
// the status pill is present for every status that the seed places in the
// store.

import { STATUS_LABELS, type OrderStatus } from "@/lib/types";

describe("OrderStatus rendering", () => {
  it("STATUS_LABELS covers every OrderStatus", () => {
    const statuses: OrderStatus[] = ["placed", "acknowledged", "out_for_delivery", "delivered", "cancelled"];
    for (const s of statuses) {
      expect(STATUS_LABELS[s]).toBeTruthy();
      expect(STATUS_LABELS[s].length).toBeGreaterThan(0);
    }
  });
});

import { describe, expect, it, vi } from "vitest";
import { renderToStaticMarkup } from "react-dom/server";

vi.mock("next/navigation", () => ({
  redirect: () => {
    throw new Error("redirect called");
  },
}));

vi.mock("@/lib/auth/session", () => ({
  getSession: () => ({ retailerId: "r-pilot-1" }),
}));

vi.mock("@/lib/db/store", () => ({
  getDistributor: () => undefined,
  listOrders: () => [],
}));

import OrdersPage from "./page";

describe("OrdersPage", () => {
  it("renders the Active / Closed tablist", () => {
    const html = renderToStaticMarkup(<OrdersPage searchParams={{}} />);
    expect(html).toContain('role="tablist"');
    expect(html).toContain("Active");
    expect(html).toContain("Closed");
    expect(html).toContain("/dashboard/orders?status=active");
    expect(html).toContain("/dashboard/orders?status=closed");
  });

  it("renders the active empty-state when group=active and 0 rows", () => {
    const html = renderToStaticMarkup(<OrdersPage searchParams={{ status: "active" }} />);
    expect(html).toContain("No active orders right now");
  });

  it("renders the closed empty-state when group=closed and 0 rows", () => {
    const html = renderToStaticMarkup(<OrdersPage searchParams={{ status: "closed" }} />);
    expect(html).toContain("No closed orders yet");
  });
});
